export function hashUserAgent(ua: string | null): string {
  if (!ua) return ''
  return crypto.createHash('sha256').update(ua).digest('hex').slice(0, 16)
}

/**
 * Result of acquiring a claim lock
 */
export interface ClaimLockResult {
  locked: boolean
